parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let deck;

try {
  deck = JSON.parse(cleaned);

  if (!deck.cards || !Array.isArray(deck.cards)) {
    throw new Error("Invalid deck format");
  }
} catch (error) {
  deck = {
    title: "Generated Flashcards",
    cards: [
      {
        type: "question",
        prompt: "Study Aura generated a flashcard response, but it could not be parsed. What should you do?",
        answer: "Try again",
        hint: "Repeat the generation process.",
        explanation: "Sometimes AI output formatting can fail. Retrying usually fixes the JSON structure."
      }
    ]
  };
}

const normalizedCards = deck.cards.map((card) => ({
  type: card.type === "fill_blank" ? "fill_blank" : "question",
  prompt: String(card.prompt || "Untitled flashcard"),
  answer: String(card.answer || "No answer provided"),
  hint: String(card.hint || "Think about the key idea."),
  explanation: String(card.explanation || "Review the related lesson content.")
}));

return [
  {
    json: {
      deck: {
        title: String(deck.title || "Study Aura Flashcards"),
        cards: normalizedCards
      },
      fallback: false
    }
  }
];

